INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (2, 2, '2', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (3, 2, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (4, 2, '4', 'Ahlaki ve etik değerlere uygun davranır.');
INSERT INTO position_categories (id, positionId, name) VALUES (3, 1, 'İletişim Becerisi');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (5, 3, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
