INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (12, 4, '12', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (5, 1, 'Kalite Odaklılık');
