INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (17, 6, '17', 'Çalışma ortamında iyi ilişkiler kurar ve korur.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (18, 6, '18', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (19, 6, '19', 'Takım ruhuna uyumlu yaklaşımda bulunur.');
