INSERT INTO position_categories (id, positionId, name) VALUES (9, 1, 'Sonuç Odaklılık');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (28, 9, '28', 'Mesleki motivasyonu yüksektir ve işini severek yapar.');
