INSERT INTO position_categories (id, positionId, name) VALUES (10, 1, 'İş Disiplini ve Tutum');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (31, 10, '1', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (32, 10, '2', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (33, 10, '3', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (34, 10, '4', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (11, 1, 'Ürün Kalitesi ve Standartlara Uyum');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (35, 11, '5', 'Ürünleri reçetelere uygun hazırlar. Ürünlerin her seferinde aynı kalite ve tatta olmasını sağlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (36, 11, '6', 'Et pişirme tekniklerine hakimdir. Şirket standartlarına uygun pişirme yapar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (37, 11, '7', 'Patates kızartma standartlarını bilir, doğru şekilde uygular.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (38, 11, '8', 'Peynir çubukları, soğan halkası, nugget vb. ürünleri doğru sürede uygun sıcaklıkta pişirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (39, 11, '9', 'Ekmek kesimini ve burger süslemesini standartlara uygun olarak yapar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (40, 11, '10', 'Kızartma yağı TPM ölçümünü doğru olarak yapar.İç ısı standardını sağlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (41, 11, '11', 'Yağ filtre işlemini standartlara uygun olarak yapar. Koruyucu materyalleri kullanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (12, 1, 'Gıda Güvenliği ve Hijyen');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (42, 12, '12', 'Ürünlerin son kullanma tarihine dikkat eder. Zayii olmasına izin vermez. (FIFO-İlk Giren İlk Çıkar)');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (43, 12, '13', 'Sebzeleri standartlara uygun şekilde yıkar.');

